// Normalizar payload + gerar source_id idempotente
const item = $input.item.json;
const body = item.body || {};
const sender = body.sender || 'unknown';
const text = (body.message && body.message.text) || '';
const reason = body.reason || 'unspecified';
const message_id = body.message_id || `${sender}-${Date.now()}`;
const instance = body.instance || 'cartorio-2notas-uberlandia';
const canal = body.canal || 'whatsapp';

// Inbox URL fallback (sempre retornado mesmo se Chatwoot falhar)
const inbox_url = `https://chatwoot.2notasudi.com.br/app/accounts/1/conversations?search=${encodeURIComponent(sender)}`;

return { json: {
  sender,
  text,
  reason,
  message_id,
  instance,
  canal,
  inbox_url,
  // Campos consumidos pelo node Chatwoot (n8n-nodes-chatwoot v1.0.2)
  // operation: createConversation + sendMessage
  chatwoot: {
    inbox_id: 0,  // ENV: CHATWOOT_INBOX_ID (default 0 em dev)
    account_id: 0,  // ENV: CHATWOOT_ACCOUNT_ID
    contact: {
      phone_number: sender,
      name: sender
    },
    conversation: {
      source_id: message_id,
      custom_attributes: {
        handoff_reason: reason,
        origin: 'cartorio-bot',
        canal: canal
      }
    },
    message: {
      content: text,
      message_type: 'incoming'
    }
  }
}};
